import { cacheTag } from 'next/cache';

export interface Post {
  id: number;
  title: string;
  content: string;
  createdAt: Date;
}

// In-memory store simulating a database
const posts: Post[] = [
  {
    id: 1,
    title: 'Welcome to Posts',
    content: 'This is a sample post to get started.',
    createdAt: new Date('2026-07-17T10:00:00Z'),
  },
  {
    id: 2,
    title: 'Next.js Cache Components',
    content: 'Using `use cache` and `cacheTag` for caching data.',
    createdAt: new Date('2026-07-17T11:00:00Z'),
  },
];

let nextId = 3;

export function addPost(title: string, content: string): Post {
  const post: Post = {
    id: nextId++,
    title,
    content,
    createdAt: new Date(),
  };
  posts.push(post);
  return post;
}

export async function getPosts(): Promise<Post[]> {
  'use cache';
  cacheTag('posts');

  // Simulate a database query delay
  return posts.slice().sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime());
}

'use server';

import { updateTag } from 'next/cache';
import { revalidatePath } from 'next/cache';
import { addPost } from '@/app/lib/data';

export async function createPost(formData: FormData) {
  const title = formData.get('title') as string | null;
  const content = formData.get('content') as string | null;

  if (!title || !content) {
    throw new Error('Title and content are required');
  }

  addPost(title, content);

  // Immediately expire the "posts" cache tag so the next request
  // blocks and fetches fresh data — no stale content is served.
  updateTag('posts');

  // Invalidate the page route's render cache so the page re-renders
  // with the fresh posts data.
  revalidatePath('/');
}

import { getPosts } from '@/app/lib/data';
import { createPost } from '@/app/actions';

export default async function Home() {
  const posts = await getPosts();

  return (
    <main style={{ maxWidth: 640, margin: '0 auto', padding: 24 }}>
      <h1>Posts</h1>

      <form action={createPost} style={{ marginBottom: 32, display: 'flex', flexDirection: 'column', gap: 8 }}>
        <input
          name="title"
          placeholder="Post title"
          required
          style={{ padding: 8, border: '1px solid #ccc', borderRadius: 4 }}
        />
        <textarea
          name="content"
          placeholder="Post content"
          required
          rows={3}
          style={{ padding: 8, border: '1px solid #ccc', borderRadius: 4 }}
        />
        <button
          type="submit"
          style={{ padding: '8px 16px', background: '#0070f3', color: '#fff', border: 'none', borderRadius: 4, cursor: 'pointer' }}
        >
          Create Post
        </button>
      </form>

      <section>
        <h2>All Posts</h2>
        {posts.length === 0 ? (
          <p>No posts yet.</p>
        ) : (
          <ul style={{ listStyle: 'none', padding: 0 }}>
            {posts.map((post) => (
              <li
                key={post.id}
                style={{ marginBottom: 16, padding: 16, border: '1px solid #eee', borderRadius: 8 }}
              >
                <h3 style={{ margin: '0 0 4px' }}>{post.title}</h3>
                <p style={{ margin: '0 0 4px', color: '#555' }}>{post.content}</p>
                <small style={{ color: '#999' }}>
                  {post.createdAt.toLocaleDateString('en-US', {
                    year: 'numeric',
                    month: 'long',
                    day: 'numeric',
                    hour: '2-digit',
                    minute: '2-digit',
                  })}
                </small>
              </li>
            ))}
          </ul>
        )}
      </section>
    </main>
  );
}
